Extensions.ExtractScript:
param(
    [xml] $Document
);

$scriptsDir = 'C:\ProgramData\Winhance\Unattend\Scripts\';
foreach( $file in $Document.unattend.Extensions.File ) {
    $path = [System.Environment]::ExpandEnvironmentVariables(
        $file.GetAttribute( 'path' )
    );
    if( $path.StartsWith( $scriptsDir ) ) {
        mkdir -Path $scriptsDir -ErrorAction 'SilentlyContinue';
    }
    $encoding = switch( [System.IO.Path]::GetExtension( $path ) ) {
        { $_ -in '.ps1', '.xml' } { [System.Text.Encoding]::UTF8; }
        { $_ -in '.reg', '.vbs', '.js' } { [System.Text.UnicodeEncoding]::new( $false, $true ); }
        default { [System.Text.Encoding]::Default; }
    };
    [System.IO.File]::WriteAllBytes( $path, ( $encoding.GetPreamble() + $encoding.GetBytes( $file.InnerText.Trim() ) ) );
}

Extensions.File:
@echo off
echo Creating 8GB RAM disk at R:

if not exist "C:\Program Files\SoftPerfect RAM Disk\ramdiskws.exe" (
    echo ERROR: SoftPerfect RAM Disk is not installed. Skipping RAM disk creation.
    exit /b 1
)

"C:\Program Files\SoftPerfect RAM Disk\ramdiskws.exe" add -size:8192 -letter:R -fs:ntfs -label:"RAMDisk" -save

mkdir R:\Temp
mkdir R:\BrowserCache

exit /b 0

@echo off
echo Redirecting browser cache to R:\BrowserCache

set CACHE=R:\BrowserCache

:: Chrome
for %%I in ("%PROGRAMDATA%\Microsoft\Windows\Start Menu\Programs\Google Chrome.lnk") do (
  powershell -NoProfile -Command "$s=(New-Object -ComObject WScript.Shell).CreateShortcut('%%~fI'); if(-not $s.Arguments.Contains('--disk-cache-dir')){$s.Arguments+=' --disk-cache-dir=\"%CACHE%\" --disk-cache-size=4096000000'}; $s.Save()"
)

:: Edge
for %%I in ("%PROGRAMDATA%\Microsoft\Windows\Start Menu\Programs\Microsoft Edge.lnk") do (
  powershell -NoProfile -Command "$s=(New-Object -ComObject WScript.Shell).CreateShortcut('%%~fI'); if(-not $s.Arguments.Contains('--disk-cache-dir')){$s.Arguments+=' --disk-cache-dir=\"%CACHE%\" --disk-cache-size=4096000000'}; $s.Save()"
)

:: Opera GX
for %%I in ("%PROGRAMDATA%\Microsoft\Windows\Start Menu\Programs\Opera GX Browser.lnk") do (
  powershell -NoProfile -Command "$s=(New-Object -ComObject WScript.Shell).CreateShortcut('%%~fI'); if(-not $s.Arguments.Contains('--disk-cache-dir')){$s.Arguments+=' --disk-cache-dir=\"%CACHE%\" --disk-cache-size=4096000000'}; $s.Save()"
)

exit /b 0
